                    new DialogueChoice { text = "\"Protect me, and I'll make sure the Crown's trail runs through your ledger before it runs through the Harpers'.\"", nextNodeId = "partner", effects = new[] { new FlagClause { key = "faction.fist", op = FlagOp.AddInt, amount = -1 } } },
                    new DialogueChoice { text = "\"Try to sell me. I'll be fascinated to see who's still solvent after.\"", nextNodeId = "threat" },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "roen", speaker = "Quill-and-Ledger Mas",
                text = "*(A dry, appraising nod.)* Alleywind chose you over a Harper payday. *(He sets down the spectacles.)* You understand what that's worth? Roen doesn't choose. Roen *calculates*, and he calculated that you're a better bet than the people who own his sister's leash. The Guild respects that math even when it doesn't like it. *(He slides a token across the counter — a candle stamped with a closed eye.)* You're not a problem we sell. You're a partner we watch. Show that to any Guild door in the Gate and it'll open. Lose Roen, and it won't. He's your credit rating, miracle. Mind it.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "act1.guild_ally", op = FlagOp.SetTrue }, new FlagClause { key = "act1.guild_token", op = FlagOp.SetTrue }, new FlagClause { key = "companion.roen.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "owed", speaker = "Quill-and-Ledger Mas",
                text = "*(He consults a ledger that may or may not be real.)* The cell favor. Yes. *(He taps the page.)* Here's the elegant thing about owing the Guild: the debt is the protection. A miracle we're owed by is a miracle no one else gets to collect on without going through us first — and going through us is expensive. *(a thin smile)* So your favor isn't a leash, it's a *fence*, in both senses. Pay it when the Crown's in hand and we'll call it even. Until then, you're under the Guild's roof by virtue of being in our debt. The Harpers will hate it. That's a service we provide free of charge.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "act1.guild_debt_is_shield", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "partner", speaker = "Quill-and-Ledger Mas",
                text = "*(The clerk's calm sharpens into genuine interest.)* The Crown's trail through my ledger before the Harpers'. *(He steeples his fingers.)* Now *that* is a number I can love. The Harpers deal in secrets they keep; the Guild deals in secrets we *sell back*, which is far more lucrative and only slightly less honest. *(He nods, once, a deal closing.)* Done. You feed me the trail, I feed you doors, blades, and the Harpers' own movements — we have ears in every cell in the Gate, as you may recall. Partners, miracle. The Guild's first walking-dead account. I'll have to invent a new column.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "act1.guild_partner", op = FlagOp.SetTrue }, new FlagClause { key = "act1.guild_feeds_harper_intel", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "threat", speaker = "Quill-and-Ledger Mas",
                text = "*(For the first time, the spectacles come off and stay off, and the killer is briefly visible under the clerk.)* ...You know, most things that threaten me are dead by morning, and you've already managed the dead part, which removes my usual leverage. *(He almost smiles.)* I respect a creditor who can't be collected. Fine. I won't sell you — not from fear, understand, from *interest.* A miracle that threatens the Guild and walks out is a story worth more than the bounty. *(he replaces the spectacles)* Go on. But miracle? The Guild remembers who threatens it. We're very patient. We learned it from the church.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "act1.guild_wary", op = FlagOp.SetTrue }, new FlagClause { key = "faction.fist", op = FlagOp.AddInt, amount = -1 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Quill-and-Ledger Mas",
                text = "*(He returns to his ledger, already pricing his next three secrets.)* One last figure, freely given, which I never do, so attend. *(He does not look up.)* The Heretic, the church, the Harpers — they all want you for what you'll let them *do* with you. The Guild's the only power in this city that wants you for what you *are*, which is a very expensive thing that hasn't been priced yet. *(now he looks up)* When everyone else has spent you, miracle, come back. We'll still be here, and we'll still be the only ones who never asked you to be a symbol. Just an account. There's a strange kind of mercy in that. It's the only kind the Gilded Gate sells.",
            });

            Act1HubFenceDialogue = g;
        }

        private void BuildAct1HubPreacherDialogue()
        {
            var g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "act1.hub.preacher";
            g.startNodeId = "0";

            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "Choir Streetpreacher",
                text = "*(Not the herald — a younger one, unmasked, standing on a crate in the Lower City with the specific radiance of someone who has found the one true answer.)* —and they tell you the dead are KEPT, friends, kept safe and sorted by a just god, but I say to you the dead are THROWN AWAY, walled living for the crime of doubt — *(he sees you, and his whole face changes)* — you. *You.* You walked out of the Wall. You are the proof of every word. Tell them. Tell them what you saw.",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "act1.preacher_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "Choir Streetpreacher",
                text = "*(The small crowd turns. Grief-faced, most of them. People from the harvest-quarters, people who've lost.)* They'll believe you. You're the miracle. One word from you and half this corner signs to the Choir tonight — *(his eyes are shining)* — and we are SO close, do you understand, Aldric is so close, and you are the sign we've prayed for. So. Will you tell them the truth you carry? Or will you let the church keep selling them a kept god while their dead dissolve?",
                choices = new[]
                {
                    new DialogueChoice { text = "\"The dead ARE thrown away. I saw it. But Aldric's cure is becoming the disease — don't trade one Wall for his.\"", nextNodeId = "nuance" },
                    new DialogueChoice { text = "\"Tell them yourself. I won't be anyone's proof — not the church's, not yours.\"", nextNodeId = "refuse", effects = new[] { new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 4 } } },
                    new DialogueChoice { text = "[PERSUADE 16] \"You're not saving them. You're recruiting their grief. The man who poisoned their wells is the man you preach for.\"", nextNodeId = "expose", checkAbility = Ability.Charisma, checkDC = 16, failNodeId = "zeal" },
                    new DialogueChoice { text = "\"Aldric's right. Tell them I said so.\"", nextNodeId = "endorse", effects = new[] { new FlagClause { key = "faction.choir", op = FlagOp.AddInt, amount = 8 }, new FlagClause { key = "act1.endorsed_choir", op = FlagOp.SetTrue } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "nuance", speaker = "Choir Streetpreacher",
                text = "*(The radiance flickers — he was not braced for a miracle who agrees and warns in the same breath.)* ...Both? *(slowly, to the crowd's unease)* You say the Wall is real AND the cure is rotting? *(He looks lost for the first time, a true believer handed a true complication.)* But — if both are true, then there is no clean side, and I have been preaching a clean side, and these people came to me for a clean side because their grief cannot hold two things at once... *(quietly, just to you)* What do I tell them, then? When the truth has no clean side? I am not sure grief can survive a sermon that complicated.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "act1.preacher_unsettled", op = FlagOp.SetTrue }, new FlagClause { key = "act1.choir_doubt_seeded", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "refuse", speaker = "Choir Streetpreacher",
                text = "*(He deflates, and then — to his credit — nods.)* ...You won't be a symbol. *(quietly)* Do you know, that might be the most honest thing anyone connected to this miracle has said. We've all been so busy deciding what you mean that none of us asked whether you wanted to mean anything. *(He steps down off the crate.)* I'll tell them myself, then. My own words, my own grief, not borrowed from a dead thing's face. *(a beat)* It'll convince fewer of them. It should. A truth that needs a miracle to sell it was never quite a truth.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "act1.preacher_humbled", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 3 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "expose", speaker = "Choir Streetpreacher",
                text = "*(The word lands in the open air, in front of the grieving crowd, and you watch it do its terrible work.)* ...The man who — *(he goes white)* — no. No, Aldric's harvest is the *cure*, it's temporary, it's — *(but a woman in the crowd is already weeping a different kind of weeping, the kind that comes when a comfort curdles)* — you've — do you know what you've *done?* You've taken the one thing these people had left, which was a side to be on, and you've shown them it has their own wells' poison on its hands. *(quietly, devastated)* They came here to stop hurting. Now they'll just hurt *accurately.* I don't know if that's mercy or cruelty. I don't think you do either.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "act1.choir_exposed", op = FlagOp.SetTrue }, new FlagClause { key = "faction.choir", op = FlagOp.AddInt, amount = -8 }, new FlagClause { key = "act1.crowd_disillusioned", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "zeal", speaker = "Choir Streetpreacher",
                text = "*(Whatever you reached for, his faith is younger and harder than your argument.)* Nice try, agent — church, Harper, whoever sent you. *(to the crowd, radiance restored)* See how they come to discredit the one man who'd free your dead! *(He's winning them back; grief wants a clean side, and he's offering one.)* The miracle himself walked out of the Wall, and still they send liars to muddy it. *(quietly, to you, certain)* You'll see. When the Wall comes down and the dead come home, you'll wish you'd stood on this corner. They always do.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "act1.preacher_unmoved", op = FlagOp.SetTrue }, new FlagClause { key = "faction.choir", op = FlagOp.AddInt, amount = 2 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "endorse", speaker = "Choir Streetpreacher",
                text = "*(He nearly falls off the crate.)* The miracle ENDORSES the Choir! *(The crowd surges; names are being signed; grief has found its clean side and a dead man's blessing on it.)* You won't regret this — when the Wall falls, your name will be the first they carve in the freed stone — *(he's weeping with joy, and a dozen grieving people are signing their names to Aldric's cause on the strength of your face)* — bless you, Returned, bless you, the sign we prayed for. *(And somewhere, you feel it: the Choir's count of the faithful ticking up, and under it, the harvest's count of the dead, the two numbers that were always the same number.)*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "act1.choir_empowered", op = FlagOp.SetTrue }, new FlagClause { key = "aldric.provisional", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Sister Garrow",
                text = "*(low, as you walk on)* My church on one corner, his Choir on the next, both promising the grieving a god who keeps them. *(She watches the crowd disperse.)* And here is the thing neither pulpit will say, Returned: those people do not want a true god or a false one. They want their dead back, and both sides have learned to sell that, and neither can deliver it, and the harvest grinds on under both sermons. *(quietly)* You are the only one on this whole street who actually walked out of the place they're all preaching about. Be careful what you tell them. A word from a real miracle is worth a thousand from a man on a crate — and worth, I begin to fear, exactly as much harm.",
            });

            Act1HubPreacherDialogue = g;
        }
    }
}
